#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int volumes[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &volumes[i]);
    }
    for (int i = 0; i < N; i++) {
        double sum = 0;
        for (int j = 0; j < N; j++) {
            sum += volumes[j];
        }
        double expected = 1.0;
        double prob = (double)volumes[i] / sum;
        expected = 1 / prob;
        printf("%.6f ", expected);
    }
    return 0;
}

