code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] volumes = new int[N];
        for (int i = 0; i < N; i++) {
            volumes[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            double sum = 0;
            for (int j = 0; j < N; j++) {
                sum += volumes[j];
            }
            double expected = 1.0;
            double prob = (double)volumes[i] / sum;
            expected = 1 / prob;
            System.out.printf("%.6f ", expected);
        }
    }
}

