const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const N = parseInt(readline());
const volumes = readline().split(' ').map(Number);
for (let i = 0; i < N; i++) {
    let sum = 0;
    for (let j = 0; j < N; j++) {
        sum += volumes[j];
    }
    let expected = 1.0;
    let prob = volumes[i] / sum;
    expected = 1 / prob;
    process.stdout.write(expected.toFixed(6) + ' ');
}

